import React from 'react';

export default function LiveMap({ singlePin, singleCoords, height = '100%' }) {
  return (
    <div style={{ height, width: '100%', background: '#E3F2FD', borderRadius: 12, border: '1px solid #B0BEC5', position: 'relative', overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <div style={{ position: 'absolute', inset: 0, opacity: 0.15, background: 'radial-gradient(circle, #000 10%, transparent 11%)', backgroundSize: '12px 12px' }} />
      <div style={{ textAlign: 'center', zIndex: 1, padding: 20 }}>
        <div style={{ fontSize: 24, marginBottom: 4 }}>🗺️</div>
        <div style={{ fontSize: 12, fontWeight: 700, color: '#1565C0' }}>Engineered Geographic Canvas Map Grid</div>
        {singlePin && singleCoords ? (
          <div style={{ fontSize: 10, color: '#546E7A', fontFamily: 'monospace', marginTop: 4 }}>Lat: {singleCoords.lat}, Lng: {singleCoords.lng}</div>
        ) : (
          <div style={{ fontSize: 10, color: '#546E7A', marginTop: 4 }}>Rendering continuous aggregate marker telemetry data logs</div>
        )}
      </div>
    </div>
  );
}
